@namespace Lumeo

<button class="@CssClass" @onclick="State.Toggle" title="Toggle sidebar" @attributes="AdditionalAttributes">
    @if (State?.IsCollapsed == true)
    {
        <Blazicon Svg="Lucide.PanelLeftOpen" class="h-4 w-4" />
    }
    else
    {
        <Blazicon Svg="Lucide.PanelLeftClose" class="h-4 w-4" />
    }
</button>

@code {
    [CascadingParameter] public SidebarProvider.SidebarState State { get; set; } = default!;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground h-9 w-9 {Class}".Trim();
}
